# WebSocket server
class WebSocketServer:
    def __init__(self):
        self.clients = []
        self.led = Pin(2, Pin.OUT)
        self.led.value(0)
        
    def generate_accept_key(self, key):
        GUID = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11"
        combined = key + GUID
        hash_obj = hashlib.sha1(combined.encode())
        return ubinascii.b2a_base64(hash_obj.digest()).decode().strip()
        
    def handle_client(self, client_socket):
        try:
            # WebSocket handshake
            request = client_socket.recv(1024).decode()
            if "Upgrade: websocket" not in request:
                return
                
            # Extract key
            key_line = [line for line in request.split('\n') if line.startswith('Sec-WebSocket-Key:')]
            if not key_line:
                return
                
            key = key_line[0].split(':')[1].strip()
            accept_key = self.generate_accept_key(key)
            
            # Send handshake response
            response = f"HTTP/1.1 101 Switching Protocols\r\n"
            response += f"Upgrade: websocket\r\n"
            response += f"Connection: Upgrade\r\n"
            response += f"Sec-WebSocket-Accept: {accept_key}\r\n\r\n"
            
            client_socket.send(response.encode())
            
            # Add client to list
            self.clients.append(client_socket)
            
            print("New WebSocket client connected")
            
            # Handle messages
            while True:
                try:
                    data = client_socket.recv(1024)
                    if not data:
                        break
                        
                    # Parse WebSocket frame
                    if len(data) > 2:
                        message = self.parse_websocket_frame(data)
                        if message:
                            self.handle_message(message)
                            
                except Exception as e:
                    print("Client disconnected:", e)
                    break
                    
        except Exception as e:
            print("Error handling client:", e)
        finally:
            if client_socket in self.clients:
                self.clients.remove(client_socket)
            client_socket.close()
            
    def parse_websocket_frame(self, data):
        try:
            # Simple WebSocket frame parsing
            if len(data) < 2:
                return None
                
            # Check if it's a text frame
            if data[0] & 0x80 == 0x80 and data[0] & 0x0F == 1:
                # Extract payload length
                payload_len = data[1] & 0x7F
                if payload_len == 126:
                    payload_len = int.from_bytes(data[2:4], 'big')
                    offset = 4
                elif payload_len == 127:
                    payload_len = int.from_bytes(data[2:10], 'big')
                    offset = 10
                else:
                    offset = 2
                    
                # Extract payload
                payload = data[offset:offset+payload_len]
                return payload.decode('utf-8')
        except:
            pass
        return None
        
    def handle_message(self, message):
        try:
            data = ujson.loads(message)
            action = data.get('action', '')
            
            if action == 'turn_on':
                self.led.value(1)
                print("LED turned ON")
            elif action == 'turn_off':
                self.led.value(0)
                print("LED turned OFF")
            elif action == 'toggle':
                self.led.value(not self.led.value())
                print("LED toggled")
                
        except Exception as e:
            print("Error processing message:", e)
            
    def start_server(self):
        # Create socket
        server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        server_socket.bind(('0.0.0.0', 8080))
        server_socket.listen(5)
        
        print("WebSocket server listening on port 8080")
        
        while True:
            try:
                client_socket, addr = server_socket.accept()
                print("Client connected from:", addr)
                
                # Handle each client in a separate thread
                import _thread
                _thread.start_new_thread(self.handle_client, (client_socket,))
                
            except Exception as e:
                print("Server error:", e)

# Start server
server = WebSocketServer()
server.start_server()